using System.ComponentModel.DataAnnotations;

namespace RecipeHub.Models;

public class Recipe
{
    public int Id { get; set; }

    [Required, StringLength(100)]
    public string Title { get; set; } = string.Empty;

    public string Category { get; set; } = string.Empty;

    [Required, MinLength(1)]
    public List<string> Ingredients { get; set; } = [];

    [Required, MinLength(1)]
    public List<string> Steps { get; set; } = [];

    public List<int> Ratings { get; set; } = [];

    public double AverageRating => Ratings.Count > 0 ? Ratings.Average() : 0;
}

using RecipeHub.Models;

namespace RecipeHub.Services;

public class RecipeService
{
    private readonly List<Recipe> _recipes;
    private int _nextId;

    public RecipeService()
    {
        _recipes =
        [
            new Recipe
            {
                Id = 1, Title = "Classic Margherita Pizza", Category = "Italian",
                Ingredients = ["Pizza dough", "Tomato sauce", "Fresh mozzarella", "Basil", "Olive oil"],
                Steps = ["Preheat oven to 475°F.", "Roll out dough and spread sauce.", "Add mozzarella slices.", "Bake for 10-12 minutes.", "Top with fresh basil and drizzle olive oil."],
                Ratings = [5, 4, 5, 4]
            },
            new Recipe
            {
                Id = 2, Title = "Spaghetti Carbonara", Category = "Italian",
                Ingredients = ["Spaghetti", "Pancetta", "Eggs", "Parmesan cheese", "Black pepper"],
                Steps = ["Cook spaghetti al dente.", "Fry pancetta until crispy.", "Whisk eggs with parmesan.", "Toss hot pasta with pancetta.", "Stir in egg mixture off heat.", "Season with black pepper."],
                Ratings = [5, 5, 4]
            },
            new Recipe
            {
                Id = 3, Title = "Chicken Tikka Masala", Category = "Indian",
                Ingredients = ["Chicken breast", "Yogurt", "Tikka spice mix", "Tomato puree", "Cream", "Onion", "Garlic"],
                Steps = ["Marinate chicken in yogurt and spices for 2 hours.", "Grill or pan-fry chicken pieces.", "Sauté onion and garlic.", "Add tomato puree and simmer.", "Add cream and cooked chicken.", "Simmer for 10 minutes."],
                Ratings = [5, 4, 5, 5]
            },
            new Recipe
            {
                Id = 4, Title = "Vegetable Pad Thai", Category = "Asian",
                Ingredients = ["Rice noodles", "Tofu", "Bean sprouts", "Peanuts", "Lime", "Soy sauce", "Tamarind paste"],
                Steps = ["Soak rice noodles in warm water.", "Press and cube tofu, then pan-fry.", "Stir-fry vegetables.", "Add noodles and sauce.", "Top with peanuts, bean sprouts, and lime."],
                Ratings = [4, 4, 3]
            },
            new Recipe
            {
                Id = 5, Title = "Beef Tacos", Category = "Mexican",
                Ingredients = ["Ground beef", "Taco shells", "Lettuce", "Tomato", "Cheddar cheese", "Sour cream", "Taco seasoning"],
                Steps = ["Brown ground beef with taco seasoning.", "Warm taco shells.", "Assemble with lettuce, tomato, cheese, and sour cream."],
                Ratings = [4, 5, 4, 4]
            },
            new Recipe
            {
                Id = 6, Title = "Chocolate Chip Cookies", Category = "Desserts",
                Ingredients = ["Butter", "Sugar", "Brown sugar", "Eggs", "Vanilla", "Flour", "Baking soda", "Chocolate chips"],
                Steps = ["Cream butter and sugars.", "Beat in eggs and vanilla.", "Mix in flour and baking soda.", "Fold in chocolate chips.", "Bake at 375°F for 9-11 minutes."],
                Ratings = [5, 5, 5, 4, 5]
            },
            new Recipe
            {
                Id = 7, Title = "Guacamole", Category = "Mexican",
                Ingredients = ["Avocados", "Lime juice", "Cilantro", "Onion", "Jalapeño", "Salt"],
                Steps = ["Mash avocados to desired consistency.", "Mix in lime juice, cilantro, onion, and jalapeño.", "Season with salt.", "Serve immediately with tortilla chips."],
                Ratings = [5, 4]
            },
            new Recipe
            {
                Id = 8, Title = "Miso Soup", Category = "Asian",
                Ingredients = ["Dashi stock", "Miso paste", "Tofu", "Wakame seaweed", "Green onion"],
                Steps = ["Heat dashi stock.", "Dissolve miso paste into the stock.", "Add cubed tofu and wakame.", "Garnish with sliced green onion."],
                Ratings = [4, 4, 5]
            },
        ];
        _nextId = 9;
    }

    public IReadOnlyList<string> GetCategories() =>
        _recipes.Select(r => r.Category).Distinct().Order().ToList();

    public IReadOnlyList<Recipe> GetByCategory(string category) =>
        _recipes.Where(r => r.Category.Equals(category, StringComparison.OrdinalIgnoreCase)).ToList();

    public Recipe? GetById(int id) =>
        _recipes.FirstOrDefault(r => r.Id == id);

    public void AddRating(int recipeId, int stars)
    {
        var recipe = GetById(recipeId);
        if (recipe is not null && stars is >= 1 and <= 5)
        {
            recipe.Ratings.Add(stars);
        }
    }

    public void AddRecipe(Recipe recipe)
    {
        recipe.Id = _nextId++;
        _recipes.Add(recipe);
    }
}

