@page "/category/{CategoryName}"
@inject RecipeHub.Services.RecipeService RecipeService

<PageTitle>@CategoryName Recipes - RecipeHub</PageTitle>

<h1>@CategoryName Recipes</h1>

<nav aria-label="breadcrumb">
    <ol class="breadcrumb">
        <li class="breadcrumb-item"><a href="">Home</a></li>
        <li class="breadcrumb-item active">@CategoryName</li>
    </ol>
</nav>

@if (recipes.Count == 0)
{
    <div class="alert alert-info">No recipes found in this category.</div>
}
else
{
    <div class="row">
        @foreach (var recipe in recipes)
        {
            <div class="col-md-6 mb-3">
                <div class="card h-100">
                    <div class="card-body">
                        <h5 class="card-title">@recipe.Title</h5>
                        <p class="card-text text-muted">
                            @if (recipe.Ratings.Count > 0)
                            {
                                <span>@RenderStars(recipe.AverageRating) (@recipe.Ratings.Count ratings)</span>
                            }
                            else
                            {
                                <span>No ratings yet</span>
                            }
                        </p>
                        <p class="card-text">@recipe.Ingredients.Count ingredients · @recipe.Steps.Count steps</p>
                        <a href="recipe/@recipe.Id" class="btn btn-primary">View Recipe</a>
                    </div>
                </div>
            </div>
        }
    </div>
}

@code {
    [Parameter]
    public string CategoryName { get; set; } = string.Empty;

    private IReadOnlyList<RecipeHub.Models.Recipe> recipes = [];

    protected override void OnParametersSet()
    {
        recipes = RecipeService.GetByCategory(CategoryName);
    }

    private static string RenderStars(double rating)
    {
        int full = (int)Math.Round(rating);
        return new string('★', full) + new string('☆', 5 - full);
    }
}

@page "/recipe/{Id:int}"
@inject RecipeHub.Services.RecipeService RecipeService

<PageTitle>@(recipe?.Title ?? "Recipe") - RecipeHub</PageTitle>

@if (recipe is null)
{
    <div class="alert alert-warning">Recipe not found.</div>
}
else
{
    <nav aria-label="breadcrumb">
        <ol class="breadcrumb">
            <li class="breadcrumb-item"><a href="">Home</a></li>
            <li class="breadcrumb-item"><a href="category/@recipe.Category">@recipe.Category</a></li>
            <li class="breadcrumb-item active">@recipe.Title</li>
        </ol>
    </nav>

    <h1>@recipe.Title</h1>
    <p class="text-muted">Category: @recipe.Category</p>

    <h3>Ingredients</h3>
    <ul class="list-group mb-3">
        @foreach (var ingredient in recipe.Ingredients)
        {
            <li class="list-group-item">@ingredient</li>
        }
    </ul>

    <h3>Steps</h3>
    <ol class="list-group list-group-numbered mb-4">
        @foreach (var step in recipe.Steps)
        {
            <li class="list-group-item">@step</li>
        }
    </ol>

    <div class="card mb-4">
        <div class="card-body">
            <h4 class="card-title">Rate this Recipe</h4>
            @if (recipe.Ratings.Count > 0)
            {
                <p>Average: @recipe.AverageRating.ToString("F1") / 5 (@recipe.Ratings.Count ratings)</p>
            }
            <StarRating RecipeId="recipe.Id" />
        </div>
    </div>
}

@code {
    [Parameter]
    public int Id { get; set; }

    private RecipeHub.Models.Recipe? recipe;

    protected override void OnParametersSet()
    {
        recipe = RecipeService.GetById(Id);
    }
}

@rendermode InteractiveServer
@inject RecipeHub.Services.RecipeService RecipeService

<div class="d-inline-block">
    @for (int i = 1; i <= 5; i++)
    {
        var star = i;
        <span role="button"
              style="font-size: 1.8rem; cursor: pointer; color: @(star <= (hoveredStar ?? selectedStar) ? "#ffc107" : "#dee2e6");"
              @onclick="() => SubmitRating(star)"
              @onmouseover="() => hoveredStar = star"
              @onmouseout="() => hoveredStar = null"
              title="@star star(s)">★</span>
    }
</div>

@if (submitted)
{
    <div class="text-success mt-2">
        <strong>Thanks! You rated this @selectedStar star(s).</strong>
    </div>
}

@code {
    [Parameter, EditorRequired]
    public int RecipeId { get; set; }

    private int selectedStar;
    private int? hoveredStar;
    private bool submitted;

    private void SubmitRating(int stars)
    {
        selectedStar = stars;
        RecipeService.AddRating(RecipeId, stars);
        submitted = true;
    }
}

