@page "/submit"
@rendermode InteractiveServer
@inject RecipeHub.Services.RecipeService RecipeService
@inject NavigationManager Navigation

<PageTitle>Submit a Recipe - RecipeHub</PageTitle>

<h1>📝 Submit a Recipe</h1>

<nav aria-label="breadcrumb">
    <ol class="breadcrumb">
        <li class="breadcrumb-item"><a href="">Home</a></li>
        <li class="breadcrumb-item active">Submit Recipe</li>
    </ol>
</nav>

@if (submitted)
{
    <div class="alert alert-success">
        <strong>Recipe submitted!</strong> Your recipe "<strong>@Model!.Title</strong>" has been added.
        <a href="recipe/@submittedId">View it here</a>.
    </div>
}
else
{
    <EditForm Model="Model" OnValidSubmit="HandleSubmit" FormName="submit-recipe">
        <DataAnnotationsValidator />
        <ValidationSummary />

        <div class="mb-3">
            <label class="form-label">Title</label>
            <InputText @bind-Value="Model!.Title" class="form-control" placeholder="e.g. Grandma's Apple Pie" />
            <ValidationMessage For="() => Model!.Title" />
        </div>

        <div class="mb-3">
            <label class="form-label">Category</label>
            <InputSelect @bind-Value="Model!.Category" class="form-select">
                <option value="">-- Select a category --</option>
                @foreach (var cat in RecipeService.GetCategories())
                {
                    <option value="@cat">@cat</option>
                }
                <option value="Other">Other</option>
            </InputSelect>
            <ValidationMessage For="() => Model!.Category" />
        </div>

        <div class="mb-3">
            <label class="form-label">Ingredients (one per line)</label>
            <InputTextArea @bind-Value="ingredientsText" class="form-control" rows="5"
                           placeholder="1 cup flour&#10;2 eggs&#10;1/2 cup sugar" />
            @if (ingredientsError is not null)
            {
                <div class="text-danger">@ingredientsError</div>
            }
        </div>

        <div class="mb-3">
            <label class="form-label">Steps (one per line)</label>
            <InputTextArea @bind-Value="stepsText" class="form-control" rows="5"
                           placeholder="Preheat oven to 350°F.&#10;Mix dry ingredients.&#10;Bake for 30 minutes." />
            @if (stepsError is not null)
            {
                <div class="text-danger">@stepsError</div>
            }
        </div>

        <button type="submit" class="btn btn-success" disabled="@isSubmitting">
            @(isSubmitting ? "Submitting..." : "Submit Recipe")
        </button>
        <a href="" class="btn btn-outline-secondary ms-2">Cancel</a>
    </EditForm>
}

@code {
    private RecipeFormModel? Model { get; set; }

    private string ingredientsText = string.Empty;
    private string stepsText = string.Empty;
    private string? ingredientsError;
    private string? stepsError;
    private bool submitted;
    private bool isSubmitting;
    private int submittedId;

    protected override void OnInitialized() => Model ??= new();

    private void HandleSubmit()
    {
        ingredientsError = null;
        stepsError = null;

        var ingredients = ParseLines(ingredientsText);
        var steps = ParseLines(stepsText);

        if (ingredients.Count == 0)
        {
            ingredientsError = "Please add at least one ingredient.";
            return;
        }
        if (steps.Count == 0)
        {
            stepsError = "Please add at least one step.";
            return;
        }

        isSubmitting = true;

        var recipe = new RecipeHub.Models.Recipe
        {
            Title = Model!.Title,
            Category = Model.Category,
            Ingredients = ingredients,
            Steps = steps,
        };

        RecipeService.AddRecipe(recipe);
        submittedId = recipe.Id;
        submitted = true;
        isSubmitting = false;
    }

    private static List<string> ParseLines(string text) =>
        text.Split('\n', StringSplitOptions.RemoveEmptyEntries | StringSplitOptions.TrimEntries)
            .Where(l => !string.IsNullOrWhiteSpace(l))
            .ToList();

    private class RecipeFormModel
    {
        [System.ComponentModel.DataAnnotations.Required(ErrorMessage = "Title is required.")]
        [System.ComponentModel.DataAnnotations.StringLength(100)]
        public string Title { get; set; } = string.Empty;

        [System.ComponentModel.DataAnnotations.Required(ErrorMessage = "Please select a category.")]
        public string Category { get; set; } = string.Empty;
    }
}

